  --color-success-bg: rgba(34, 197, 94, 0.12);

  --shadow-card-sm: 0 1px 3px rgba(0,0,0,0.25);
  --shadow-dropdown: 0 4px 16px rgba(0,0,0,0.4), 0 0 0 1px rgba(255,240,210,0.04);

  --bg-selection: rgba(212,168,83,0.1);
  --bg-selection-active: rgba(212,168,83,0.18);

  --loader-color: #D4A853;

  color-scheme: dark;
  color: var(--text-primary);
  background-color: var(--bg-primary);
}

a {
  font-weight: 500;
  color: #C4943E;
  text-decoration: inherit;
}
a:hover {
  color: #B8862D;
}

body {
  margin: 0;
  display: flex;
  place-items: center;
  min-width: 320px;
  min-height: 100vh;
  overflow-x: hidden;
  background-color: var(--bg-primary);
  color: var(--text-primary);
  transition: background-color 0.2s ease, color 0.2s ease;
}
